import React, { useState, useEffect, useContext, useRef, useCallback } from 'react';
import { chatAPI, authAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';
import io from 'socket.io-client';

// SVG Icons
const SearchIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" className="search-icon" viewBox="0 0 16 16">
    <path d="M11.742 10.344a6.5 6.5 0 1 0-1.397 1.398h-.001c.03.04.062.078.098.115l3.85 3.85a1 1 0 0 0 1.415-1.414l-3.85-3.85a1.007 1.007 0 0 0-.115-.1zM12 6.5a5.5 5.5 0 1 1-11 0 5.5 5.5 0 0 1 11 0z" />
  </svg>
);

const SendIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="currentColor" viewBox="0 0 16 16">
    <path d="M15.854.146a.5.5 0 0 1 .11.54l-5.819 14.547a.75.75 0 0 1-1.329.124l-3.178-4.995L.643 7.184a.75.75 0 0 1 .124-1.33L15.314.037a.5.5 0 0 1 .54.11ZM6.636 10.07l2.761 4.338L14.13 2.576 6.636 10.07Zm6.787-8.201L1.591 6.602l4.339 2.76 7.494-7.493Z" />
  </svg>
);

const TrashIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
    <path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5m2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5m3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0z"/>
    <path d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1zM4.118 4 4 4.059V13a1 1 0 0 0 1 1h6a1 1 0 0 0 1-1V4.059L11.882 4zM2.5 3h11V2h-11z"/>
  </svg>
);

const BellIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="currentColor" viewBox="0 0 16 16">
    <path d="M8 16a2 2 0 0 0 2-2H6a2 2 0 0 0 2 2Zm.104-14.995a1 1 0 1 0-2.208 0A5.002 5.002 0 0 0 3 5c0 1.098-.5 5.5-1.5 6.5h13C13.5 10.5 13 6.098 13 5a5.002 5.002 0 0 0-4.896-4.995Z"/>
  </svg>
);

const ChatPage = () => {
  const { user } = useContext(AuthContext);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [unreadCounts, setUnreadCounts] = useState({});
  const [notification, setNotification] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const socket = useRef(null);
  const messagesEndRef = useRef(null);
  const selectedUserRef = useRef(null);
  const usersRef = useRef([]);

  const normalizeMessage = useCallback((msg) => ({
    ...msg,
    senderId:
      typeof msg.senderId === 'object' && msg.senderId !== null
        ? msg.senderId._id
        : msg.senderId,
    receiverId:
      typeof msg.receiverId === 'object' && msg.receiverId !== null
        ? msg.receiverId._id
        : msg.receiverId,
  }), []);

  const dedupeClientMessages = useCallback((messageList) => {
    const seen = new Map();

    return messageList
      .map(normalizeMessage)
      .filter((msg) => {
        const messageId = msg?._id?.toString?.();
        const senderKey = msg.senderId?.toString?.() || '';
        const receiverKey = msg.receiverId?.toString?.() || '';
        const timestampKey = new Date(msg.timestamp).getTime();
        const signature = messageId || `${senderKey}|${receiverKey}|${msg.message}`;
        const previousTimestamp = seen.get(signature);
        const isDuplicate =
          typeof previousTimestamp === 'number' &&
          Math.abs(timestampKey - previousTimestamp) < 300;

        if (isDuplicate) {
          return false;
        }

        seen.set(signature, timestampKey);
        return true;
      });
  }, [normalizeMessage]);

  const handleReceiveMessage = useCallback((data) => {
    const activeUserId = selectedUserRef.current?._id;

    if (data.senderId === activeUserId) {
      setMessages((prev) => dedupeClientMessages([...prev, data]));
      return;
    }

    setUnreadCounts((prev) => ({
      ...prev,
      [data.senderId]: (prev[data.senderId] || 0) + 1,
    }));

    const sender = usersRef.current.find((item) => item._id === data.senderId);
    setNotification({
      senderId: data.senderId,
      senderName: sender?.name || 'Student',
      senderMeta: sender?.email || 'Student account',
      preview: data.message,
      tone: 'message',
    });
  }, [dedupeClientMessages]);

  useEffect(() => {
    socket.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socket.current.emit('user_join', user?._id);
    socket.current.on('receive_message', handleReceiveMessage);

    return () => {
      socket.current.off('receive_message', handleReceiveMessage);
      socket.current.disconnect();
    };
  }, [user, handleReceiveMessage]);

  useEffect(() => {
    selectedUserRef.current = selectedUser;
  }, [selectedUser]);

  useEffect(() => {
    usersRef.current = users;
  }, [users]);

  useEffect(() => {
    if (!notification) return undefined;
    const timer = setTimeout(() => setNotification(null), 4000);
    return () => clearTimeout(timer);
  }, [notification]);

  useEffect(() => {
    if (messagesEndRef.current) {
      const parent = messagesEndRef.current.parentElement;
      if (parent) {
        parent.scrollTo({ top: parent.scrollHeight, behavior: 'smooth' });
      }
    }
  }, [messages]);

  useEffect(() => {
    fetchUsers();
    fetchUnreadCounts();
  }, []);

  const fetchUnreadCounts = async () => {
    try {
      const res = await chatAPI.getUnreadCounts();
      if (res.data.success) {
        setUnreadCounts(res.data.countsByUser || {});
      }
    } catch (err) {
      console.error('Failed to fetch unread counts', err);
    }
  };

  const filteredUsers = users.filter((student) => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return true;
    return (
      student.name?.toLowerCase().includes(query) ||
      student.email?.toLowerCase().includes(query)
    );
  });

  const fetchUsers = async () => {
    try {
      const res = await authAPI.getAllStudents();
      setUsers(res.data.students || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch users');
    }
  };

  const getContactsEmptyMessage = () => {
    if (searchTerm.trim()) {
      return 'No students matched your search.';
    }

    return 'No student conversations yet.';
  };

  const handleSelectUser = async (student) => {
    setSelectedUser(student);
    setNotification(null);

    // Clear unread counts for this user
    setUnreadCounts((prev) => ({ ...prev, [student._id]: 0 }));
    try {
      await chatAPI.markAsRead(student._id);
    } catch (e) {
      console.error('Failed to mark as read', e);
    }

    setLoading(true);
    try {
      const res = await chatAPI.getChatHistory(student._id);
      setMessages(dedupeClientMessages(res.data.messages || []));
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch chat history');
    } finally {
      setLoading(false);
    }
  };

  const handleSendMessage = async () => {
    if (!newMessage.trim() || !selectedUser) return;

    try {
      await chatAPI.sendMessage({
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      socket.current.emit('send_message', {
        senderId: user._id,
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      setMessages((prev) => dedupeClientMessages([
        ...prev,
        {
          senderId: user._id,
          senderName: user.name,
          message: newMessage.trim(),
          timestamp: new Date().toISOString(),
        },
      ]));
      setNewMessage('');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to send message');
    }
  };

  const handleClearChat = async () => {
    if (!selectedUser) return;

    if (window.confirm(`Are you sure you want to clear the chat with ${selectedUser.name}? This cannot be undone.`)) {
      try {
        await chatAPI.clearChatHistory(selectedUser._id);
        setMessages([]);
      } catch (err) {
        setError(err.response?.data?.error || 'Failed to clear chat history');
      }
    }
  };

  const formatTime = (timestamp) =>
    new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  const getInitials = (name) => {
    if (!name) return '?';
    return name.charAt(0).toUpperCase();
  };

  const truncateNotificationPreview = (text) => {
    if (!text) return '';
    return text.length > 88 ? `${text.slice(0, 88)}...` : text;
  };

  const handleOpenNotification = () => {
    if (!notification?.senderId) return;
    const matchedUser = users.find((item) => item._id === notification.senderId);
    if (matchedUser) {
      handleSelectUser(matchedUser);
    }
    setNotification(null);
  };

  return (
    <div className="container-fluid py-3 chat-page-wrapper d-flex flex-column">
      <div className="portal-page-header">
        <span className="portal-page-kicker">Messages</span>
        <h1 className="portal-page-title">Student Conversations</h1>
        <p className="portal-page-subtitle">
          Keep communication organized with our premium messaging interface.
        </p>
      </div>

      {error && (
        <div className="alert alert-danger alert-dismissible fade show" role="alert">
          {error}
          <button type="button" className="btn-close" onClick={() => setError('')}></button>
        </div>
      )}

      {notification && (
        <div className="premium-chat-notification-layer">
          <div className="premium-chat-notification" role="alert">
            <div className="premium-chat-notification-icon">
              <BellIcon />
            </div>
            <div className="premium-chat-notification-body">
              <div className="premium-chat-notification-title-row">
                <strong>New message</strong>
                <button
                  type="button"
                  className="premium-chat-notification-close"
                  onClick={() => setNotification(null)}
                  aria-label="Dismiss notification"
                >
                  x
                </button>
              </div>
              <div className="premium-chat-notification-sender">
                {notification.senderName}
                {notification.senderMeta ? ` • ${notification.senderMeta}` : ''}
              </div>
              <div className="premium-chat-notification-preview">
                {truncateNotificationPreview(notification.preview)}
              </div>
              <button
                type="button"
                className="premium-chat-notification-action"
                onClick={handleOpenNotification}
              >
                Open chat
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="premium-chat-shell">
        <aside className={`premium-chat-sidebar ${selectedUser ? 'chat-pane-hidden-mobile' : ''}`}>
          <div className="premium-chat-toolbar">
            <h4 className="mb-0 fw-bold">Inbox</h4>
            <div className="premium-search-box">
              <SearchIcon />
              <input
                type="text"
                className="form-control premium-search-input"
                placeholder="Search students..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          <div className="premium-chat-list">
            {filteredUsers.length === 0 ? (
              <div className="premium-chat-empty-state">{getContactsEmptyMessage()}</div>
            ) : (
              filteredUsers.map((student) => (
                <button
                  key={student._id}
                  className={`premium-chat-user ${selectedUser?._id === student._id ? 'active' : ''}`}
                  onClick={() => handleSelectUser(student)}
                >
                  <div className="chat-avatar">
                    {getInitials(student.name)}
                  </div>
                  <div className="premium-chat-contact-body">
                    <div className="premium-chat-contact-row">
                      <div className="premium-chat-contact-meta">
                        <span className="fw-bold text-truncate">{student.name}</span>
                        <div className="text-muted small text-truncate">{student.email}</div>
                      </div>
                      {unreadCounts[student._id] > 0 && (
                        <span className="badge bg-danger rounded-pill">{unreadCounts[student._id]}</span>
                      )}
                    </div>
                  </div>
                </button>
              ))
            )}
          </div>
        </aside>

        <section className={`premium-chat-main ${!selectedUser ? 'chat-pane-hidden-mobile' : ''}`}>
          {selectedUser ? (
            <>
              <div className="premium-chat-header">
                <div className="premium-chat-header-main">
                  <button 
                    className="premium-mobile-back-btn d-md-none"
                    onClick={() => setSelectedUser(null)}
                    type="button"
                    aria-label="Back to inbox"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" viewBox="0 0 16 16">
                      <path fillRule="evenodd" d="M11.354 1.646a.5.5 0 0 1 0 .708L5.707 8l5.647 5.646a.5.5 0 0 1-.708.708l-6-6a.5.5 0 0 1 0-.708l6-6a.5.5 0 0 1 .708 0z"/>
                    </svg>
                  </button>
                  <div className="chat-avatar">
                    {getInitials(selectedUser.name)}
                  </div>
                  <div className="premium-chat-header-copy">
                    <h5 className="mb-0 fw-bold">{selectedUser.name}</h5>
                    <small className="text-muted d-none d-sm-block">{selectedUser.email}</small>
                  </div>
                </div>
                <div className="premium-chat-header-actions">
                  <button 
                    className="btn btn-sm btn-outline-danger d-flex align-items-center gap-1 rounded-pill px-3"
                    onClick={handleClearChat}
                    title="Clear Chat History"
                  >
                    <TrashIcon /> <span className="d-none d-md-inline">Clear History</span>
                  </button>
                </div>
              </div>

              <div className="premium-chat-messages">
                {loading ? (
                  <div className="d-flex justify-content-center align-items-center h-100">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading...</span>
                    </div>
                  </div>
                ) : messages.length === 0 ? (
                  <div className="d-flex flex-column justify-content-center align-items-center h-100 text-muted">
                    <div className="chat-avatar mb-3" style={{ width: '64px', height: '64px', fontSize: '1.5rem', background: 'var(--bg-secondary)', color: 'var(--text-muted)', boxShadow: 'none' }}>
                      {getInitials(selectedUser.name)}
                    </div>
                    <h5>Start the conversation with {selectedUser.name.split(' ')[0]}</h5>
                    <p>Send a message below to begin.</p>
                  </div>
                ) : (
                  messages.map((msg, index) => {
                    const isOutgoing = msg.senderId === user._id;
                    return (
                      <div key={index} className={`message-wrapper ${isOutgoing ? 'outgoing' : 'incoming'}`}>
                        <div className={`premium-message-stack ${isOutgoing ? 'align-end' : 'align-start'}`}>
                          <div className="premium-message">
                            {msg.message}
                          </div>
                          <span className="premium-message-time">{formatTime(msg.timestamp)}</span>
                        </div>
                      </div>
                    );
                  })
                )}
                <div ref={messagesEndRef} />
              </div>

              <div className="premium-chat-input-area">
                <div className="premium-input-wrapper">
                  <input
                    type="text"
                    className="premium-message-input"
                    placeholder="Type your message..."
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  />
                  <button
                    className="premium-send-btn"
                    type="button"
                    onClick={handleSendMessage}
                    disabled={!newMessage.trim()}
                  >
                    <SendIcon />
                  </button>
                </div>
              </div>
            </>
          ) : (
            <div className="d-flex flex-column justify-content-center align-items-center h-100">
              <div className="p-4 rounded-circle mb-3 text-muted" style={{ background: 'var(--bg-surface-solid)' }}>
                <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" fill="currentColor" viewBox="0 0 16 16">
                  <path d="M2 1a1 1 0 0 0-1 1v8a1 1 0 0 0 1 1h9.586a2 2 0 0 1 1.414.586l2 2V2a1 1 0 0 0-1-1H2zm12-1a2 2 0 0 1 2 2v12.793a.5.5 0 0 1-.854.353l-2.853-2.853a1 1 0 0 0-.707-.293H2a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h12z" />
                  <path d="M5 6a1 1 0 1 1-2 0 1 1 0 0 1 2 0zm4 0a1 1 0 1 1-2 0 1 1 0 0 1 2 0zm4 0a1 1 0 1 1-2 0 1 1 0 0 1 2 0z" />
                </svg>
              </div>
              <h4 className="fw-bold">Your Messages</h4>
              <p className="text-muted">Select a student from the sidebar to open the conversation.</p>
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default ChatPage;
